import{a as e}from"./DataTable-BgCjEQPy.js";var t={getAll:async(t,n)=>(await e.get(`/${t}`,{params:n})).data,getById:async(t,n)=>(await e.get(`/${t}/${n}`)).data,create:async(t,n)=>(await e.post(`/${t}`,n)).data,update:async(t,n,r)=>(await e.put(`/${t}/${n}`,r)).data,delete:async(t,n)=>(await e.delete(`/${t}/${n}`)).data,importCSV:async(t,n)=>{let r=new FormData;return r.append(`file`,n),(await e.post(`/${t}/import`,r,{headers:{"Content-Type":`multipart/form-data`}})).data},getSalesByProduct:async(t,n)=>(await e.get(`/sales/by-product/${t}`,{params:n})).data};export{t};